import{_ as t,o,c as i,a2 as s}from"./chunks/framework.B72_uj9U.js";const p=JSON.parse('{"title":"Chapter 5: Tool Systems Deep Dive","description":"How agents interact with the world through tools — schema design, validation, execution models, composition, and security.","frontmatter":{"title":"Chapter 5: Tool Systems Deep Dive","description":"How agents interact with the world through tools — schema design, validation, execution models, composition, and security."},"headers":[],"relativePath":"learn/linear/05-tool-systems-deep-dive/index.md","filePath":"learn/linear/05-tool-systems-deep-dive/index.md"}'),a={name:"learn/linear/05-tool-systems-deep-dive/index.md"};function l(n,e,r,d,h,c){return o(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="tool-systems-deep-dive" tabindex="-1">Tool Systems Deep Dive <a class="header-anchor" href="#tool-systems-deep-dive" aria-label="Permalink to &quot;Tool Systems Deep Dive&quot;">​</a></h1><p>Tools are how a coding agent escapes the confines of text generation and actually does things in the world. A tool might read a file, execute a shell command, search a codebase, or write code to disk. The tool system is the bridge between the language model&#39;s intentions and real-world side effects. Getting this system right is what separates a useful agent from a dangerous one.</p><p>This chapter covers the complete tool lifecycle from definition to execution. We start with JSON Schema, the lingua franca for describing tool interfaces to language models. We then examine how to design tool descriptions that models understand reliably, how to validate inputs before execution, and how to handle the results. You will learn the difference between synchronous and asynchronous execution, how to compose simple tools into complex workflows, and how to implement security boundaries.</p><p>By the end of this chapter, you will have a thorough understanding of tool system design and be ready to implement specific tools in the following chapters. You will know not just how tools work mechanically, but how to design them so that language models use them correctly — a subtly different and critically important skill.</p><h2 id="learning-objectives" tabindex="-1">Learning Objectives <a class="header-anchor" href="#learning-objectives" aria-label="Permalink to &quot;Learning Objectives&quot;">​</a></h2><ul><li>Design tool schemas using JSON Schema that language models can interpret accurately</li><li>Write tool descriptions that minimize misuse and maximize correct invocations</li><li>Implement validation strategies that catch invalid inputs before execution</li><li>Choose between synchronous and asynchronous execution models based on tool characteristics</li><li>Compose simple tools into higher-level operations while maintaining error transparency</li><li>Apply security boundaries including sandboxing, permission models, and output sanitization</li></ul><h2 id="subchapters" tabindex="-1">Subchapters <a class="header-anchor" href="#subchapters" aria-label="Permalink to &quot;Subchapters&quot;">​</a></h2><ol><li><a href="/linear/05-tool-systems-deep-dive/01-why-tools-matter.html">Why Tools Matter</a></li><li><a href="/linear/05-tool-systems-deep-dive/02-json-schema-specification.html">JSON Schema Specification</a></li><li><a href="/linear/05-tool-systems-deep-dive/03-tool-description-design.html">Tool Description Design</a></li><li><a href="/linear/05-tool-systems-deep-dive/04-validation-strategies.html">Validation Strategies</a></li><li><a href="/linear/05-tool-systems-deep-dive/05-execution-models.html">Execution Models</a></li><li><a href="/linear/05-tool-systems-deep-dive/06-sync-vs-async-execution.html">Sync vs Async Execution</a></li><li><a href="/linear/05-tool-systems-deep-dive/07-error-propagation.html">Error Propagation</a></li><li><a href="/linear/05-tool-systems-deep-dive/08-tool-result-formats.html">Tool Result Formats</a></li><li><a href="/linear/05-tool-systems-deep-dive/09-tool-categories.html">Tool Categories</a></li><li><a href="/linear/05-tool-systems-deep-dive/10-tool-composition.html">Tool Composition</a></li><li><a href="/linear/05-tool-systems-deep-dive/11-tool-discovery.html">Tool Discovery</a></li><li><a href="/linear/05-tool-systems-deep-dive/12-security-considerations.html">Security Considerations</a></li><li><a href="/linear/05-tool-systems-deep-dive/13-designing-for-llms.html">Designing for LLMs</a></li><li><a href="/linear/05-tool-systems-deep-dive/14-summary.html">Summary</a></li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Chapter 4 (understanding the agentic loop)</li></ul>',10)])])}const u=t(a,[["render",l]]);export{p as __pageData,u as default};
